                    {"id": "q7", "type": "multi_select", "question": "Case: A hospital wants to reduce patient wait times. What are the three queuing theory factors? (Select all that apply)", "options": ["Arrival Variability", "Service Time Variability", "Capacity Constraints", "Appointment Scheduling", "Staff Efficiency", "Patient Volume", "Equipment Availability", "Process Optimization"], "correct_answers": [0, 1, 2], "correct_answer": "Arrival Variability, Service Time Variability, Capacity Constraints", "explanation": "Queuing theory: Wait = f(Arrival variability, Service variability, Utilization). Smooth arrivals, consistent service, right capacity."},
                    {"id": "q8", "type": "multi_select", "question": "Case: An airline wants to improve ancillary revenue. Structure:? (Select all that apply)", "options": ["Pre-Flight", "In-Flight", "Post-Flight", "Business Travelers, Leisure Travelers", "Baggage, Seats, Food, Upgrades"], "correct_answers": [0, 1, 2], "correct_answer": "Pre-Flight, In-Flight, Post-Flight", "explanation": "Customer journey stages: Pre-flight (bags, seats, priority), In-flight (food, wifi, upgrades), Post-flight (lounge, transfer). Covers all touchpoints."},
                    {"id": "q9", "type": "multi_select", "question": "Case: A media company's advertising revenue is declining. What are the three revenue levers? (Select all that apply)", "options": ["Inventory", "Pricing", "Fill Rate", "Ad Sales Team", "Advertiser Demand", "Content Quality", "Audience Size", "CPM Rates"], "correct_answers": [0, 1, 2], "correct_answer": "Inventory (Ad Slots), Pricing (CPM), Fill Rate (% Sold)", "explanation": "Ad revenue = Inventory × Price × Fill Rate. More inventory, higher CPMs, better sell-through. These are the three revenue levers."},
