class DrillRequest(BaseModel):
    drill_type: str
    difficulty: str
    drill_id: str = None  # Optional: specific drill ID to start


def get_db(request: Request):
    return request.app.state.db


@router.post("/generate")
async def get_drill(drill_request: DrillRequest, request: Request):
    """Get a pre-generated drill for the user"""
    user = await get_current_user(request)
    db = get_db(request)
    
    drill_type = drill_request.drill_type
    difficulty = drill_request.difficulty
    drill_id = drill_request.drill_id  # Optional specific drill ID
    
    if drill_type not in DRILL_TYPES:
        raise HTTPException(status_code=400, detail=f"Invalid drill type")
    
    if difficulty not in TIME_LIMITS:
        raise HTTPException(status_code=400, detail=f"Invalid difficulty")
    
    # Fetch available drills from MongoDB for this type/difficulty
    available_drills = await db.ai_drills.find({
        "drill_type": drill_type,
        "difficulty": difficulty
    }, {"_id": 0}).to_list(1000)
    
    if not available_drills:
        raise HTTPException(status_code=404, detail="No drills available for this combination")
    
    user_id = user.get("id") if isinstance(user, dict) else user.id
    
    # If specific drill_id is provided, find that drill
    if drill_id:
        selected_drill = None
        for d in available_drills:
            if d["id"] == drill_id:
                selected_drill = d
                break
        if not selected_drill:
            raise HTTPException(status_code=404, detail=f"Drill {drill_id} not found")
    else:
        # Original behavior: find a drill user hasn't done yet
        completed = await db.drill_completions.find({
            "user_id": user_id,
            "drill_type": drill_type,
            "difficulty": difficulty
        }).to_list(100)
        
        completed_drill_ids = [c.get("drill_id") for c in completed]
        
        available_new = [d for d in available_drills if d["id"] not in completed_drill_ids]
        
        if not available_new:
            selected_drill = random.choice(available_drills)
        else:
            selected_drill = available_new[0]
    
    # Create a drill session
    session_id = f"drill-{uuid.uuid4().hex[:12]}"
    
    drill_session = {
        "id": session_id,
        "user_id": user_id,
        "drill_id": selected_drill["id"],
        "drill_type": drill_type,
        "difficulty": difficulty,
        "questions": selected_drill["questions"],
        "created_at": datetime.utcnow(),
        "completed": False
    }
    await db.drill_sessions.insert_one(drill_session)
    
    # Get the correct difficulty label based on drill type
    difficulty_label = difficulty_labels_by_type.get(drill_type, {}).get(difficulty, difficulty.capitalize())
    time_limit = time_limits_by_type.get(drill_type, {}).get(difficulty, 600)
    
    return {
        "drill_session_id": session_id,
        "drill_id": selected_drill["id"],
        "drill_type": DRILL_TYPES[drill_type]["name"],
        "difficulty": difficulty,
        "difficulty_label": difficulty_label,  # Add this field
        "questions": selected_drill["questions"],
        "time_limit": time_limit,  # Use drill-type-specific time limit
        "total_questions": len(selected_drill["questions"])
    }


@router.post("/evaluate")
async def evaluate_answer(request: Request):
    """Evaluate a user's answer"""
    user = await get_current_user(request)
    body = await request.json()
    
    question = body.get("question", {})
    user_answer = body.get("user_answer", "")
    
    if question.get("type") == "multiple_choice":
        user_answer_str = str(user_answer).strip()
        is_correct = user_answer_str == question.get("correct_answer")
        return {
            "is_correct": is_correct,
            "correct_answer": question.get("correct_answer"),
            "explanation": question.get("explanation", "")
        }
    
    if question.get("type") == "multi_select":
        # user_answer should be a list of selected indices
        correct_indices = set(question.get("correct_answers", []))
        user_indices = set(user_answer) if isinstance(user_answer, list) else set()
        is_correct = user_indices == correct_indices
        
        # Format correct answer for display
        correct_options = [question["options"][i] for i in sorted(correct_indices)]
        correct_answer_display = ", ".join(correct_options)
        
        return {
            "is_correct": is_correct,
            "correct_answer": correct_answer_display,
            "explanation": question.get("explanation", "")
        }
    
    # Text input - check against acceptable answers
    user_answer_str = str(user_answer).strip()
    acceptable = question.get("acceptable_answers", [question.get("correct_answer", "")])
    
    # Normalize answers for comparison
    def normalize(s):
        return s.lower().replace(" ", "").replace(",", "").replace("$", "").replace("%", "")
    
    user_normalized = normalize(user_answer_str)
    is_correct = any(normalize(a) == user_normalized for a in acceptable)
    
    return {
        "is_correct": is_correct,
        "correct_answer": question.get("correct_answer"),
        "explanation": question.get("explanation", "")
    }


@router.post("/complete/{session_id}")
async def complete_drill(session_id: str, request: Request):
    """Mark a drill session as complete"""
    user = await get_current_user(request)
    db = get_db(request)
    
    body = await request.json()
    score = body.get("score", 0)
    total = body.get("total", 10)
    time_taken = body.get("time_taken", 0)
    
    user_id = user.get("id") if isinstance(user, dict) else user.id
    
    # Get the session
    session = await db.drill_sessions.find_one({"id": session_id, "user_id": user_id})
    
    if not session:
        raise HTTPException(status_code=404, detail="Session not found")
    
    # Update session
    await db.drill_sessions.update_one(
        {"id": session_id},
        {"$set": {
            "completed": True,
            "score": score,
            "total": total,
            "time_taken": time_taken,
            "completed_at": datetime.utcnow()
        }}
    )
    
    # Record completion
    await db.drill_completions.insert_one({
        "user_id": user_id,
        "drill_id": session.get("drill_id"),
        "drill_type": session.get("drill_type"),
        "difficulty": session.get("difficulty"),
        "score": score,
        "total": total,
        "completed_at": datetime.utcnow()
    })
    
    return {
        "message": "Drill completed",
        "score": score,
        "total": total,
        "percentage": round((score / total) * 100) if total > 0 else 0
    }


@router.get("/score-history")
async def get_drill_score_history(request: Request):
    """Get drill score history for line chart showing progression over time"""
    user = await get_current_user(request)
    db = get_db(request)
    
    user_id = user.get("id") if isinstance(user, dict) else user.id
    
    # Get all completed drills, sorted by completion date
    completions = await db.drill_completions.find(
        {"user_id": user_id}
    ).sort("completed_at", 1).to_list(1000)
    
    # Group by drill type and create progression data
    history = {
        "case_math": [],
        "case_structuring": [],
        "charts_exhibits": []
    }
    
    # Counter for drill number per type
    drill_counter = {
        "case_math": 0,
        "case_structuring": 0,
        "charts_exhibits": 0
    }
    
    for completion in completions:
        drill_type = completion.get("drill_type")
        score = completion.get("score", 0)
        total = completion.get("total", 10)
        percentage = round((score / total) * 100) if total > 0 else 0
        
        if drill_type in history:
            drill_counter[drill_type] += 1
            history[drill_type].append({
                "drill_number": drill_counter[drill_type],
                "score": percentage,
                "date": completion.get("completed_at").isoformat() if completion.get("completed_at") else None
            })
    
    return {
        "history": history,
        "latest_scores": {
            "case_math": history["case_math"][-1]["score"] if history["case_math"] else 0,
            "case_structuring": history["case_structuring"][-1]["score"] if history["case_structuring"] else 0,
            "charts_exhibits": history["charts_exhibits"][-1]["score"] if history["charts_exhibits"] else 0
        }
    }


